select 
from sys_user
where deleted = 0

    and (username like concat('%', #{keyword}, '%') or real_name like concat('%', #{keyword}, '%') or student_no like concat('%', #{keyword}, '%'))


    and status = #{status}


    and class_id = #{classId}


    and id in (select user_id from sys_user_role where role_id = #{roleId} and deleted = 0)

order by id desc
limit #{offset}, #{pageSize}

select count(1) from sys_user where deleted = 0
and (username like concat('%', #{keyword}, '%') or real_name like concat('%', #{keyword}, '%') or student_no like concat('%', #{keyword}, '%'))
and status = #{status}
and class_id = #{classId}
and id in (select user_id from sys_user_role where role_id = #{roleId} and deleted = 0)
